package com.vidaysalud.veterinaria.medicamentoservicio.service;import com.vidaysalud.veterinaria.medicamentoservicio.dto.*;import com.vidaysalud.veterinaria.medicamentoservicio.exception.*;import com.vidaysalud.veterinaria.medicamentoservicio.model.Medicamento;import com.vidaysalud.veterinaria.medicamentoservicio.repository.MedicamentoRepository;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;@Service @RequiredArgsConstructor @Slf4j @Transactional public class MedicamentoService{private final MedicamentoRepository r;@Transactional(readOnly=true)public List<MedicamentoResponseDTO> listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public MedicamentoResponseDTO buscar(Integer id){return dto(get(id));}public MedicamentoResponseDTO crear(MedicamentoRequestDTO d){validar(d.getNombre(),null);return dto(r.save(map(new Medicamento(),d)));}public MedicamentoResponseDTO actualizar(Integer id,MedicamentoRequestDTO d){validar(d.getNombre(),id);return dto(r.save(map(get(id),d)));}public MedicamentoResponseDTO actualizarStock(Integer id,Integer stock){if(stock<0)throw new ReglaNegocioException("El stock no puede ser negativo");Medicamento m=get(id);m.setStock(stock);log.info("Stock medicamento {} -> {}",id,stock);return dto(r.save(m));}public void eliminar(Integer id){r.delete(get(id));}private Medicamento get(Integer id){return r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Medicamento no encontrado: "+id));}private void validar(String n,Integer id){r.findByNombreIgnoreCase(n.trim()).filter(x->!x.getIdMedicamento().equals(id)).ifPresent(x->{throw new DatoDuplicadoException("Medicamento duplicado");});}private Medicamento map(Medicamento m,MedicamentoRequestDTO d){m.setNombre(d.getNombre().trim());m.setDescripcion(d.getDescripcion());m.setStock(d.getStock());m.setPrecioUnitario(d.getPrecioUnitario());m.setActivo(d.getActivo()==null?true:d.getActivo());return m;}private MedicamentoResponseDTO dto(Medicamento m){return MedicamentoResponseDTO.builder().idMedicamento(m.getIdMedicamento()).nombre(m.getNombre()).descripcion(m.getDescripcion()).stock(m.getStock()).precioUnitario(m.getPrecioUnitario()).activo(m.getActivo()).build();}}